// TeamView — команда вместе с уже загруженными участниками и привязанными
// проектами: страница /orgs/{id}/teams рендерит сразу несколько команд,
// поэтому обходы TeamMembers/TeamProjects по каждой команде web-хендлер
// делает один раз при сборке страницы, а не в шаблоне.
type TeamView struct {
	Team     org.Team
	Members  []org.Member
	Projects []org.Project
}

// memberInTeam — участник организации уже состоит в команде? Нужно, чтобы не
// предлагать в select тех, кто и так уже участник (AddTeamMember и так
// идемпотентен, но лишний пункт в select только путает).
func memberInTeam(members []org.Member, userID int64) bool {
	for _, m := range members {
		if m.UserID == userID {
			return true
		}
	}
	return false
}

// projectAttached — тот же принцип для select привязки проекта.
func projectAttached(projects []org.Project, projectID int64) bool {
	for _, p := range projects {
		if p.ID == projectID {
			return true
		}
	}
	return false
}

// hasAvailableMembers — есть ли хоть один участник организации, ещё не
// состоящий в команде (кандидат для select добавления участника).
func hasAvailableMembers(members []org.Member, teamMembers []org.Member) bool {
	for _, m := range members {
		if !memberInTeam(teamMembers, m.UserID) {
			return true
		}
	}
	return false
}

// hasAvailableProjects — тот же принцип для select привязки проекта: есть ли
// хоть один проект организации, ещё не привязанный к команде.
func hasAvailableProjects(projects []org.Project, teamProjects []org.Project) bool {
	for _, p := range projects {
		if !projectAttached(teamProjects, p.ID) {
			return true
		}
	}
	return false
}

